const pregunta = ($node['Config1'].json.pregunta_usuario || '').trim();
const low = pregunta.toLowerCase();

// Objeto para almacenar los detalles del comando
const comando = {
  nombre: null,
  params: {},
  tipo: 'chat', // Default
  necesita_diff: false,
  error: null
};

// Si no es un comando, es un chat normal
if (!pregunta.startsWith('!')) {
  if (pregunta.includes('ha saltado al servidor') || pregunta.includes('joined the server')) {
    comando.error = 'Ignorado';
  } else {
    comando.necesita_diff = /(codig|commit|diff|revisa|calidad|pull request|\bpr\b|merge)/.test(low);
  }
} else {
  const partes = pregunta.split(' ');
  const cmd = partes[0].toLowerCase();

  switch (cmd) {
    case '!ayuda':
    case '!help':
      comando.nombre = 'ayuda';
      comando.tipo = 'ayuda';
      break;
    case '!kpis':
      comando.nombre = 'kpis';
      comando.tipo = 'kpis';
      break;
    case '!reporte':
      comando.nombre = 'reporte';
      comando.tipo = 'reporte';
      // Opcional: capturar número de días
      const dias = parseInt(partes[1], 10);
      if (!isNaN(dias) && dias > 0) {
        comando.params.dias = dias;
      } else {
        comando.params.dias = 7; // Default
      }
      break;
    case '!riesgos':
      comando.nombre = 'riesgos';
      comando.tipo = 'chat'; // Usará el flujo de chat pero con un contexto específico
      break;
    case '!hitos':
      comando.nombre = 'hitos';
      comando.tipo = 'chat'; // Igual que riesgos
      break;
    case '!revisar':
      comando.nombre = 'revisar';
      comando.tipo = 'chat';
      comando.necesita_diff = true;
      const repo = (partes[1] || '').toLowerCase();
      if (repo === 'backend' || repo === 'frontend') {
        comando.params.repo = repo;
      } else {
        comando.error = 'Debes especificar un repositorio: `!revisar backend` o `!revisar frontend`.';
      }
      break;
    case '!estado':
      comando.nombre = 'estado'; comando.tipo = 'chat'; comando.formato = 'estado'; break;
    case '!vencidas':
      comando.nombre = 'vencidas'; comando.tipo = 'chat'; comando.formato = 'vencidas'; break;
    case '!miembros':
      comando.nombre = 'miembros'; comando.tipo = 'chat'; comando.formato = 'miembros'; break;
    case '!commits':
      comando.nombre = 'commits'; comando.tipo = 'chat'; comando.formato = 'commits'; break;
    case '!ci':
      comando.nombre = 'ci'; comando.tipo = 'chat'; comando.formato = 'ci'; break;
    case '!progreso':
      comando.nombre = 'progreso'; comando.tipo = 'chat'; comando.formato = 'progreso'; break;
        default:
      comando.error = `Comando \`${cmd}\` no reconocido. Usa \`!ayuda\` para ver la lista de comandos.`;
      break;
  }
}

// El objeto de salida ahora es más rico en información
return [{
  json: {
    pregunta,
    comando,
    tipo: comando.error ? 'error' : comando.tipo,
    necesita_diff: comando.necesita_diff,
    formato: comando.formato || 'chat',
    usuario: $node['Config1'].json.usuario_discord
  }
}];

const row = $json || {};
let k = row.kpis_json || {};

if (typeof k === 'string') {
  try {
    k = JSON.parse(k);
  } catch (e) {
    k = {};
  }
}

const val = (v, fallback = 'N/A') => (v === undefined || v === null || v === '') ? fallback : v;

const lines = [
  'KPIs PetSafe (' + new Date(row.fecha_ejecucion).toLocaleString('es-EC') + ')',
  '',
  'Progreso sprint: ' + val(row.progreso_pct, 0) + '%',
  'Tareas vencidas: ' + val(row.tareas_vencidas, 0),
  'Velocidad: ' + val(k.velocidad_tareas_por_dia, 0) + ' tareas/dia (completadas 7d: ' + val(k.completadas_7d, 0) + ')',
  '% a tiempo: ' + val(k.pct_a_tiempo, 0) + '%',
  'Commits 14d: ' + val(k.commits_14d, 0) + ' (' + val(k.commits_por_dia, 0) + '/dia)',
  'PR avg open: ' + val(k.pr_open_time_dias, 0) + ' dias',
  'PR merge ratio 30d: ' + val(k.pr_merge_ratio_30d, 0) + '%',
  'Dias hasta fin: ' + val(k.dias_hasta_fin, 'N/A'),
  'Proyeccion: ' + val(k.proyeccion, 'N/A')
];

return [{ json: { text: lines.join('\n') } }];

const now = new Date();
const MS_PER_DAY = 86400000;
function daysBetween(from, to) {
  if (!from || !to) return null;
  const diff = new Date(to) - new Date(from);
  return Math.round(diff / 86400000);
}

function isValidDate(d) { return d instanceof Date && !Number.isNaN(d.getTime()); }
function parseDate(value) { if (!value) return null; const d = new Date(value); return isValidDate(d) ? d : null; }
function safeString(value, fallback = '') { return typeof value === 'string' ? value : fallback; }
function safeArray(value) { return Array.isArray(value) ? value : []; }
function truncate(value, max) { const str = safeString(value, ''); return str.length > max ? str.slice(0, max) : str; }
function getFirstJson(nodeName, fallback = null) { try { const item = $(nodeName).first(); return item && item.json ? item.json : fallback; } catch (e) { return fallback; } }
function getAllJson(nodeName) { try { const items = $(nodeName).all(); return Array.isArray(items) ? items.map(i => i?.json || {}) : []; } catch (e) { return []; } }
function coalesce(...values) { for (const v of values) { if (v !== undefined && v !== null && v !== '') return v; } return null; }
function simplifyCommit(c, type) { return { msg: truncate(c.commit?.message, 60), auth: truncate(c.commit?.author?.name, 20), date: c.commit?.author?.date, type: type }; }

const router = getFirstJson('Router Comandos', {});
const config = getFirstJson('Config', {});
const pregunta = safeString(router.pregunta, '').trim();
const usuario = safeString(router.usuario, 'desconocido');
const needDiff = !!router.necesita_diff;
const geminiKey = safeString(config.GEMINI_API_KEY, '');

let ctx;
const cached = getFirstJson('Redis Get CTX', {});

if (cached && cached.ctx_data) {
  // CACHE HIT!
  ctx = typeof cached.ctx_data === 'string' ? JSON.parse(cached.ctx_data) : cached.ctx_data;
} else {
  // CACHE MISS: Build Context
  const cards = getAllJson('Trello Cards');
  const lists = getAllJson('Trello Lists');
  const members = getAllJson('Trello Members');
  const bCommits = getAllJson('GH Back Commits');
  const fCommits = getAllJson('GH Front Commits');
  const bPRs = getAllJson('GH Back PRs');
  const fPRs = getAllJson('GH Front PRs');
  const historial = getAllJson('PG Historial');
  const recos = getAllJson('PG Recomendaciones');
  const hitos = getAllJson('PG Hitos');

  const tareas = cards.map(c => {
    const l = lists.find(list => list.id === c.idList);
    const m = c.idMembers?.length ? members.find(mem => mem.id === c.idMembers[0]) : null;
    return { id: c.id, nombre: c.name, lista: l ? l.name : 'Desconocida', completada: (l && l.name.toLowerCase().includes('completado')), miembro: m ? m.fullName : 'Sin asignar', vencimiento: parseDate(c.due) };
  });

  const tareasPendientes = tareas.filter(t => !t.completada);
  const vencidas = tareasPendientes.filter(t => t.vencimiento && t.vencimiento < now).length;
  const porVencer = tareasPendientes.filter(t => t.vencimiento && t.vencimiento >= now && (t.vencimiento - now) / MS_PER_DAY <= 3).length;

  const kpis = historial.length > 0 ? historial[0] : {};
  const recomendacionesPrevias = recos.slice(0, 3).map(r => ({ desc: r.descripcion, aplicada: r.aplicada }));
  const hitosActivos = hitos.filter(h => !h.completado).map(h => ({ n: h.nombre, fin: h.fecha_fin, d: daysBetween(now, parseDate(h.fecha_fin)) }));

  ctx = {
    fecha_actual: now.toISOString(),
    usuario,
    tareas: { total: tareas.length, vencidas, por_vencer_3dias: porVencer, completadas_count: tareas.filter(t => t.completada).length, recientes_completadas: tareas.filter(t => t.completada).slice(0, 15).map(t => t.nombre), resumen_todas: tareas.map(t => ({n: t.nombre, l: t.lista, c: t.completada ? 1 : 0})), distribucion: tareas.reduce((acc, t) => { acc[t.lista] = (acc[t.lista] || 0) + 1; return acc; }, {}) },
    github: { commits_back_recientes: bCommits.slice(0, 8).map(c => simplifyCommit(c, 'backend')), commits_front_recientes: fCommits.slice(0, 8).map(c => simplifyCommit(c, 'frontend')) },
    kpis_ultimo_analisis: kpis, hitos_proximos: hitosActivos.slice(0, 5), recomendaciones_previas: recomendacionesPrevias
  };
}

let diffBack = null; let diffFront = null;
if (needDiff) {
  const repo = router.comando?.params?.repo;
  if (!repo || repo === 'backend') diffBack = getFirstJson('Diff Backend', null);
  if (!repo || repo === 'frontend') diffFront = getFirstJson('Diff Frontend', null);
}
let diffInfo = null;
if (diffBack || diffFront) { diffInfo = { backend: diffBack ? truncate(JSON.stringify(diffBack), 3000) : null, frontend: diffFront ? truncate(JSON.stringify(diffFront), 3000) : null }; }
ctx.diff_commits = diffInfo;

const system_prompt = `Eres el Gestor de Proyecto IA para "PetSafe". Tu objetivo es dar respuestas precisas. REGLAS ESTRICTAS:
1. MAX 1800 caracteres. SIN MARKDOWN complejo.
2. Si preguntan por estado general: resume KPIs, tareas y fechas clave.
3. Si la pregunta es simple (ej "hay vencidas?"), responde directo.
4. Considera hitos proximos y dias hasta fin.
CONTEXTO (${now.toISOString()}):
${JSON.stringify(ctx, null, 2)}
PREGUNTA DE ${usuario}:
${pregunta || 'Pregunta no disponible'}`;

return [{ json: { system_prompt, user_prompt: pregunta, gemini_key: geminiKey, pregunta, usuario, ctx_data: ctx, from_cache: !!(cached && cached.ctx_data) } }];

const h = $node['PG Historial1']?.first()?.json || {};
const kpis = (typeof h.kpis_json === 'string' ? JSON.parse(h.kpis_json) : h.kpis_json) || {};
const cards = $node['Trello Cards1'].all().map(i=>i.json);
const total = cards.length;
const done = cards.filter(c=>c.dueComplete).length;
const overdue = cards.filter(c=>c.due && !c.dueComplete && new Date(c.due)<new Date()).length;
const pct = total>0?Math.round(done/total*100):0;
const vel = kpis.velocidad_tareas_por_dia ?? '?';
const proj = kpis.proyeccion ?? 'sin datos';
const emojiProj = proj==='on-track'?'✅':proj==='riesgo'?'⚠️':'🔴';
const lines = [
  '**📊 ESTADO DEL PROYECTO PetSafe**',
  `Progreso: **${pct}%** (${done}/${total} tareas)  ${emojiProj} ${proj}`,
  `Vencidas: **${overdue}**  |  Velocidad: **${vel}** tareas/día`,
  `Commits 14d: **${kpis.commits_14d ?? '?'}**  |  Bus factor: **${kpis.bus_factor_14d ?? '?'}**`,
  `Días hasta entrega: **${kpis.dias_hasta_fin ?? '?'}**`
];
return [{json:{respuesta: lines.join('\n')}}];

const cards = $node['Trello Cards1'].all().map(i=>i.json);
const lists = $node['Trello Lists1'].all().map(i=>i.json);
const members = $node['Trello Members1'].all().map(i=>i.json);
const listById = Object.fromEntries(lists.map(l=>[l.id,l.name]));
const memById = Object.fromEntries(members.map(m=>[m.id,m.fullName||m.username]));
const now = new Date();
const venc = cards.filter(c=>c.due&&!c.dueComplete&&new Date(c.due)<now);
if(!venc.length) return [{json:{respuesta:'✅ No hay tareas vencidas.'}}];
const lines = ['**🔴 TAREAS VENCIDAS**',''];
for(const c of venc.slice(0,10)){
  const dias = Math.floor((now-new Date(c.due))/86400000);
  const resp = (c.idMembers||[]).map(id=>memById[id]||id).join(', ') || 'sin asignar';
  lines.push(`• **${c.name}**`);
  lines.push(`  Lista: ${listById[c.idList]||'?'} | Resp: ${resp} | Hace ${dias}d`);
}
if(venc.length>10) lines.push(`...y ${venc.length-10} más`);
return [{json:{respuesta:lines.join('\n')}}];

const cards = $node['Trello Cards1'].all().map(i=>i.json);
const members = $node['Trello Members1'].all().map(i=>i.json);
const memById = Object.fromEntries(members.map(m=>[m.id,m.fullName||m.username]));
const now = new Date();
const stats = {};
for(const c of cards){
  for(const id of (c.idMembers||[])){
    const name = memById[id]||id;
    if(!stats[name]) stats[name]={asig:0,done:0,venc:0};
    stats[name].asig++;
    if(c.dueComplete) stats[name].done++;
    else if(c.due&&new Date(c.due)<now) stats[name].venc++;
  }
}
const lines = ['**👥 CARGA DEL EQUIPO**','`Miembro          | Asig | Done | Venc`'];
for(const [name,s] of Object.entries(stats)){
  const short = name.split(' ').slice(0,2).join(' ').padEnd(16);
  lines.push(`${short} |  ${String(s.asig).padStart(2)}  |  ${String(s.done).padStart(2)}  |  ${String(s.venc).padStart(2)}`);
}
return [{json:{respuesta:lines.join('\n')}}];

const bC = $node['GH Back Commits1'].all().map(i=>i.json).slice(0,5);
const fC = $node['GH Front Commits1'].all().map(i=>i.json).slice(0,5);
const fmt = (c,repo)=>`• \`${(c.sha||'').slice(0,7)}\` [${repo}] **${(c.commit?.author?.name||'?').split(' ')[0]}**: ${(c.commit?.message||'').split('\n')[0].slice(0,70)}`;
const lines = ['**📝 COMMITS RECIENTES**','**Backend:**',...bC.map(c=>fmt(c,'back')),'','**Frontend:**',...fC.map(c=>fmt(c,'front'))];
return [{json:{respuesta:lines.join('\n')}}];

const bR = $node['GH Back CI Runs'].first()?.json?.workflow_runs?.[0];
const fR = $node['GH Front CI Runs'].first()?.json?.workflow_runs?.[0];
const emo = s=>s==='success'?'✅':s==='failure'?'❌':s==='in_progress'?'🔄':'⚪';
const fmt = (r,label)=>r?`${emo(r.conclusion||r.status)} **${label}**: ${r.conclusion||r.status} | rama: ${r.head_branch} | por: ${r.actor?.login||'?'}`:`⚪ **${label}**: sin datos`;
const lines = ['**🔧 ESTADO CI/CD**',fmt(bR,'Backend'),fmt(fR,'Frontend'),'','🌐 Deploy: https://pet-safe-six.vercel.app'];
return [{json:{respuesta:lines.join('\n')}}];

const cards = $node['Trello Cards1'].all().map(i=>i.json);
const h = $node['PG Historial1']?.first()?.json||{};
const kpis=(typeof h.kpis_json==='string'?JSON.parse(h.kpis_json):h.kpis_json)||{};
const now=new Date();
const total=cards.length, done=cards.filter(c=>c.dueComplete).length;
const pend=cards.filter(c=>!c.dueComplete&&!(c.due&&new Date(c.due)<now)).length;
const venc=cards.filter(c=>c.due&&!c.dueComplete&&new Date(c.due)<now).length;
const pct=total>0?Math.round(done/total*100):0;
const bar='█'.repeat(Math.round(pct/10))+'░'.repeat(10-Math.round(pct/10));
const lines=[
  '**🏁 PROGRESO DEL SPRINT**',
  `\`[${bar}] ${pct}%\``,
  `Completadas: **${done}** | Pendientes: **${pend}** | Vencidas: **${venc}**`,
  `Velocidad: **${kpis.velocidad_tareas_por_dia??'?'}** t/día | Commits/día: **${kpis.commits_por_dia??'?'}**`,
  `Proyección: **${kpis.proyeccion??'sin datos'}** | Días hasta fin: **${kpis.dias_hasta_fin??'?'}**`
];
return [{json:{respuesta:lines.join('\n')}}];
